import{_ as a,o as r,c as o,a2 as e}from"./chunks/framework.BWuWLRhz.js";const g=JSON.parse('{"title":"🚀 Shadowrocket for iOS","description":"iOS 备选客户端（付费，需外区 Apple ID），协议支持全、规则灵活。","frontmatter":{"description":"iOS 备选客户端（付费，需外区 Apple ID），协议支持全、规则灵活。"},"headers":[],"relativePath":"clients/ios/shadowrocket.md","filePath":"clients/ios/shadowrocket.md","lastUpdated":1783252730000}'),l={name:"clients/ios/shadowrocket.md"};function s(i,t,n,d,h,p){return r(),o("div",null,[...t[0]||(t[0]=[e('<h1 id="🚀-shadowrocket-for-ios" tabindex="-1">🚀 Shadowrocket for iOS <a class="header-anchor" href="#🚀-shadowrocket-for-ios" aria-label="Permalink to &quot;🚀 Shadowrocket for iOS&quot;">​</a></h1><blockquote><p><strong>备选方案 · 付费应用</strong> | 协议支持全、一键导入方便、规则灵活。首选推荐见 <a href="./clash-mi">Clash Mi</a>（免费）。</p></blockquote><p><a href="https://apps.apple.com/us/app/shadowrocket/id932747118" target="_blank" rel="noreferrer">Shadowrocket</a>（俗称&quot;小火箭&quot;）是 iOS / iPadOS 上最常用的代理客户端，支持订阅链接、扫码和 URL Scheme 一键导入。</p><h2 id="📊-基本信息" tabindex="-1">📊 基本信息 <a class="header-anchor" href="#📊-基本信息" aria-label="Permalink to &quot;📊 基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th>项目</th><th>说明</th></tr></thead><tbody><tr><td>价格</td><td>约 $2.99（一次买断）</td></tr><tr><td>系统要求</td><td>iOS 13+ / iPadOS 13+</td></tr><tr><td>获取方式</td><td>App Store（需<strong>美区等外区 Apple ID</strong>，国区未上架）</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">INFO</p><p><strong>没有外区 Apple ID？</strong> 可以注册一个美区 Apple ID（地区选 United States，无需绑卡，礼品卡充值购买），或使用免费的 <a href="./clash-mi">Clash Mi</a> 作为替代。</p></div><h2 id="📥-下载安装" tabindex="-1">📥 下载安装 <a class="header-anchor" href="#📥-下载安装" aria-label="Permalink to &quot;📥 下载安装&quot;">​</a></h2><ol><li>App Store 登录外区 Apple ID</li><li>搜索 <strong>Shadowrocket</strong> 购买并下载</li><li>下载完成后可切回常用 Apple ID，应用保留可用</li></ol><h2 id="🚀-完整配置教程" tabindex="-1">🚀 完整配置教程 <a class="header-anchor" href="#🚀-完整配置教程" aria-label="Permalink to &quot;🚀 完整配置教程&quot;">​</a></h2><h3 id="步骤一-导入订阅-三选一" tabindex="-1">步骤一：导入订阅（三选一） <a class="header-anchor" href="#步骤一-导入订阅-三选一" aria-label="Permalink to &quot;步骤一：导入订阅（三选一）&quot;">​</a></h3><p><strong>方式 A · 一键导入（最快）</strong></p><p>在 iPhone 上用 Safari 登录<a href="https://freedomport.cc/#/dashboard" target="_blank" rel="noreferrer">会员中心</a>，在订阅链接卡片点击 <strong>Shadowrocket 图标</strong>，系统会自动唤起小火箭并添加订阅。</p><p><strong>方式 B · 扫码导入</strong></p><p>在电脑上打开会员中心，用小火箭首页右上角的 <strong>扫码按钮</strong> 扫订阅二维码。</p><p><strong>方式 C · 手动添加</strong></p><ol><li>复制会员中心的订阅链接</li><li>打开小火箭 → 首页右上角 <strong>+</strong> → 类型选择 <strong>Subscribe</strong></li><li>URL 粘贴订阅链接，备注填 <code>FreedomPort</code>，点右上角完成</li></ol><h3 id="步骤二-更新节点" tabindex="-1">步骤二：更新节点 <a class="header-anchor" href="#步骤二-更新节点" aria-label="Permalink to &quot;步骤二：更新节点&quot;">​</a></h3><p>首页下拉刷新，或长按订阅条目选择 <strong>更新</strong>，节点列表会出现在首页。</p><h3 id="步骤三-连接" tabindex="-1">步骤三：连接 <a class="header-anchor" href="#步骤三-连接" aria-label="Permalink to &quot;步骤三：连接&quot;">​</a></h3><ol><li>点选一个节点（建议先选延迟低的香港 / 日本节点）</li><li>打开顶部 <strong>连接开关</strong>，首次连接会请求添加 VPN 配置，点 <strong>允许</strong> 并验证</li><li>打开浏览器访问外网验证</li></ol><h3 id="步骤四-日常使用建议" tabindex="-1">步骤四：日常使用建议 <a class="header-anchor" href="#步骤四-日常使用建议" aria-label="Permalink to &quot;步骤四：日常使用建议&quot;">​</a></h3><ul><li><strong>全局路由</strong> 建议选 <strong>配置（规则）</strong>：国内直连、国外走代理，省流量且不影响国内应用</li><li>节点变慢时在首页点 <strong>延迟测试</strong>，换低延迟节点</li><li>看到节点上新公告后，记得更新订阅</li></ul><h2 id="❓-常见问题" tabindex="-1">❓ 常见问题 <a class="header-anchor" href="#❓-常见问题" aria-label="Permalink to &quot;❓ 常见问题&quot;">​</a></h2><p><strong>Q: 连接开关打开后立刻弹回？</strong> A: 设置 → VPN 与设备管理，删除旧的 VPN 配置后重新连接；或重启设备。</p><p><strong>Q: 节点延迟测试全部超时？</strong> A: 先更新订阅；再确认套餐有效；换 Wi-Fi / 蜂窝网络分别测试。</p><p><strong>Q: 国内 App 也走了代理变慢？</strong> A: 全局路由改为 <strong>配置（规则）</strong> 模式即可国内直连。</p><h2 id="📞-相关链接" tabindex="-1">📞 相关链接 <a class="header-anchor" href="#📞-相关链接" aria-label="Permalink to &quot;📞 相关链接&quot;">​</a></h2><ul><li>App Store：<a href="https://apps.apple.com/us/app/shadowrocket/id932747118" target="_blank" rel="noreferrer">https://apps.apple.com/us/app/shadowrocket/id932747118</a></li><li>遇到问题：<a href="./../../guide/faq">常见问题 FAQ</a> · <a href="https://freedomport.cc/#/ticket" target="_blank" rel="noreferrer">提交工单</a></li></ul>',28)])])}const u=a(l,[["render",s]]);export{g as __pageData,u as default};
